import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String safeUserInput = sanitizeInput(userInput);

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<p>User input: " + safeUserInput + "</p>");
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String userInput) {
        // Implement proper input sanitization here based on your requirements
        // For a basic example, you can use HTML escaping to encode special characters
        return userInput != null ? userInput.replaceAll("&", "&amp;")
                                        .replaceAll("<", "&lt;")
                                        .replaceAll(">", "&gt;")
                                        .replaceAll("\"", "&quot;")

